     1→// [util] Poll a prediction until it completes
     2→// - Calls Replicate API directly when provider is "replicate" (no internal API route needed)
     3→// - Falls back to internal API route for other providers (supports cookie forwarding for auth)
     4→// - Supports configurable backoff/timeouts and fixed interval mode
     5→"server-only";
     6→
     7→import Replicate from "replicate";
     8→import { status as ImageStatus } from "@/config/image-generator/enums";
     9→import { env } from "@/env/server";
    10→import logger from "@/utils/logger";
    11→
    12→const replicate = new Replicate({
    13→  auth: env.REPLICATE_API_TOKEN,
    14→});
    15→
    16→// Prevent Next.js / Vercel from caching responses
    17→replicate.fetch = (url, options) => {
    18→  return fetch(url, { cache: "no-store", ...options });
    19→};
    20→
    21→export type PredictionStatus = ImageStatus | string;
    22→
    23→export type PredictionResponse = {
    24→  id: string;
    25→  status: PredictionStatus;
    26→  output?: unknown;
    27→  error?: string | null;
    28→  created_at?: string;
    29→  [key: string]: unknown;
    30→};
    31→
    32→export type PollOptions = {
    33→  baseUrl?: string; // e.g. process.env.NEXTAUTH_URL or http://localhost:3000
    34→  provider?: string; // e.g. 'replicate' | 'leonardo'
    35→  cookie?: string; // serialized cookie header to forward auth/session
    36→  maxAttempts?: number; // default 40
    37→  initialDelayMs?: number; // default 1000
    38→  maxDelayMs?: number; // default 10000
    39→  totalTimeoutMs?: number; // default 4 minutes
    40→  fixedInterval?: boolean; // if true, use fixed interval instead of exponential backoff
    41→};
    42→
    43→function sleep(ms: number): Promise<void> {
    44→  return new Promise((resolve) => setTimeout(resolve, ms));
    45→}
    46→
    47→function backoff(attempt: number, initial: number, maxDelay: number): number {
    48→  const delay = initial * 1.2 ** attempt;
    49→  return Math.min(delay, maxDelay);
    50→}
    51→
    52→export async function pollPrediction(
    53→  predictionId: string,
    54→  {
    55→    baseUrl = process.env.NEXT_PUBLIC_SERVER_URL || "http://localhost:3000",
    56→    provider = "replicate",
    57→    cookie,
    58→    maxAttempts = 20, // Reduced from 40
    59→    initialDelayMs = 2000, // Increased from 1000
    60→    maxDelayMs = 8000, // Reduced from 10000
    61→    totalTimeoutMs = 45 * 1000, // 45 seconds (leave 15s buffer for Vercel)
    62→    fixedInterval = false, // Use fixed interval instead of exponential backoff
    63→  }: PollOptions = {},
    64→): Promise<PredictionResponse> {
    65→  // [info] Start: polling prediction
    66→  logger.debug("[POLLING] Starting prediction polling", {
    67→    predictionId,
    68→    provider,
    69→    baseUrl,
    70→    maxAttempts,
    71→    totalTimeoutMs: `${totalTimeoutMs / 1000}s`,
    72→    initialDelayMs,
    73→    fixedInterval,
    74→    mode: fixedInterval ? "fixed-interval" : "exponential-backoff",
    75→  });
    76→
    77→  const start = Date.now();
    78→  let attempt = 0;
    79→
    80→  // [debug] Log polling configuration
    81→  logger.debug("[POLLING] Polling configuration:", {
    82→    predictionId,
    83→    provider,
    84→    baseUrl,
    85→    directApiCall: provider === "replicate",
    86→  });
    87→
    88→  // Polling starts immediately (no initial delay)
    89→  // Direct Replicate API calls help reduce rate limiting by avoiding internal API overhead
    90→
    91→  while (attempt < maxAttempts && Date.now() - start < totalTimeoutMs) {
    92→    attempt += 1;
    93→
    94→    logger.debug(`[POLLING] Attempt ${attempt}/${maxAttempts}`, {
    95→      predictionId,
    96→      provider,
    97→      timeElapsed: `${Math.round((Date.now() - start) / 1000)}s`,
    98→    });
    99→
   100→    try {
   101→      // [debug] Making direct API call to Replicate
   102→      logger.debug(
   103→        `[POLLING] Making direct API call to Replicate for prediction: ${predictionId}`,
   104→      );
   105→
   106→      let data: PredictionResponse;
   107→
   108→      if (provider === "replicate") {
   109→        // Call Replicate API directly (like the test route)
   110→        const prediction = await replicate.predictions.get(predictionId);
   111→        data = prediction as unknown as PredictionResponse;
   112→      } else {
   113→        // Fallback to internal API route for other providers
   114→        const pollUrl = `${baseUrl}/api/venus-9/v2/image/prediction/${encodeURIComponent(predictionId)}?provider=${encodeURIComponent(provider)}`;
   115→        logger.debug(`[POLLING] 📡 Using internal API route: ${pollUrl}`);
   116→
   117→        const res = await fetch(pollUrl, {
   118→          method: "GET",
   119→          headers: {
   120→            Accept: "application/json",
   121→            ...(cookie ? { Cookie: cookie } : {}),
   122→          },
   123→          cache: "no-store",
   124→        });
   125→
   126→        if (!res.ok) {
   127→          throw new Error(
   128→            `API request failed: ${res.status} ${res.statusText}`,
   129→          );
   130→        }
   131→
   132→        data = (await res.json()) as PredictionResponse;
   133→      }
   134→
   135→      // [debug] Log the full response structure
   136→      logger.debug("[POLLING] Full response data:", {
   137→        data,
   138→        dataKeys: Object.keys(data || {}),
   139→        dataType: typeof data,
   140→        isArray: Array.isArray(data),
   141→      });
   142→
   143→      // [debug] Polling JSON payload
   144→      logger.debug("[POLLING] Response summary:", {
   145→        status: data?.status,
   146→        id: data?.id,
   147→        hasOutput: !!data?.output,
   148→        hasError: !!data?.error,
   149→        created_at: data?.created_at,
   150→      });
   151→
   152→      if (data?.status === ImageStatus.SUCCEDED) {
   153→        // [info] Completed: prediction succeeded
   154→        logger.debug("[POLLING] SUCCESS: Prediction completed successfully", {
   155→          predictionId,
   156→          finalStatus: data.status,
   157→          outputCount: Array.isArray(data.output)
   158→            ? data.output.length
   159→            : "not array",
   160→          duration: `${Math.round((Date.now() - start) / 1000)}s`,
   161→        });
   162→        return data;
   163→      }
   164→
   165→      if (data?.status === ImageStatus.FAILED) {
   166→        // [error] Completed: prediction failed
   167→        logger.debug("[POLLING] FAILED: Prediction failed", {
   168→          predictionId,
   169→          error: data?.error,
   170→          finalStatus: data.status,
   171→          duration: `${Math.round((Date.now() - start) / 1000)}s`,
   172→        });
   173→        return data;
   174→      }
   175→
   176→      // Continue polling for other statuses
   177→      const delay = fixedInterval
   178→        ? initialDelayMs // Fixed interval: always use initialDelayMs
   179→        : backoff(attempt - 1, initialDelayMs, maxDelayMs); // Exponential backoff
   180→
   181→      const timeElapsed = Math.round((Date.now() - start) / 1000);
   182→      logger.debug(
   183→        `[POLLING] Status: "${data?.status}" - continuing to poll...`,
   184→        {
   185→          predictionId,
   186→          attempt,
   187→          nextDelay: `${delay}ms (${delay / 1000}s)`,
   188→          mode: fixedInterval ? "fixed-interval" : "exponential-backoff",
   189→          timeElapsed: `${timeElapsed}s`,
   190→          nextPollAt: `${timeElapsed + delay / 1000}s`,
   191→        },
   192→      );
   193→
   194→      logger.debug(
   195→        `[POLLING] Sleeping for ${delay}ms (${delay / 1000}s) before next poll...`,
   196→      );
   197→      await sleep(delay);
   198→      logger.debug(
   199→        `[POLLING] Woke up after ${delay}ms sleep. Time elapsed: ${Math.round((Date.now() - start) / 1000)}s`,
   200→      );
   201→    } catch (error) {
   202→      // [warn] network or parse error, continue with backoff
   203→      logger.debug(`[POLLING] Request failed on attempt ${attempt}:`, {
   204→        error: error instanceof Error ? error.message : error,
   205→        errorType:
   206→          error instanceof Error ? error.constructor.name : typeof error,
   207→        predictionId,
   208→        provider,
   209→        attempt,
   210→      });
   211→
   212→      if (attempt >= maxAttempts) {
   213→        logger.debug("[POLLING] Max attempts reached, giving up");
   214→        throw error;
   215→      }
   216→
   217→      const delay = fixedInterval
   218→        ? initialDelayMs
   219→        : backoff(attempt - 1, initialDelayMs, maxDelayMs);
   220→      logger.debug(`[POLLING] Waiting ${delay}ms before retry...`, {
   221→        mode: fixedInterval ? "fixed-interval" : "exponential-backoff",
   222→      });
   223→      await sleep(delay);
   224→    }
   225→  }
   226→
   227→  // [error] Timed out
   228→  logger.debug(
   229→    `[POLLING] TIMEOUT: Polling timed out after ${maxAttempts} attempts`,
   230→    {
   231→      predictionId,
   232→      totalTime: `${Math.round((Date.now() - start) / 1000)}s`,
   233→      maxAttempts,
   234→      totalTimeoutMs: `${totalTimeoutMs / 1000}s`,
   235→    },
   236→  );
   237→
   238→  return {
   239→    id: predictionId,
   240→    status: ImageStatus.FAILED,
