     3→/**
     4→ * Extracts text content from a UIMessage
     5→ */
     6→export function extractTextFromUiMessage(
     7→  message: UIMessage,
     8→): string | undefined {
     9→  return extractTextFromParts(message.parts);
    10→}
    11→
    12→/**
    13→ * Extracts text content from message parts
    14→ */
    15→export function extractTextFromParts(
    16→  parts: UIMessage["parts"],
    17→): string | undefined {
    18→  const chunks: string[] = [];
    19→  for (const part of parts) {
    20→    if (part.type === "text") {
    21→      chunks.push(part.text);
    22→    }
    23→  }
    24→  const text = chunks.join("");
    25→  return text.trim().length ? text : undefined;
    26→}
    27→
    28→/**
    29→ * Extracts the latest user text from a list of UIMessages
    30→ */
    31→export function extractLatestUserTextFromUiMessages(
    32→  messages: UIMessage[],
    33→): string | undefined {
    34→  for (let i = messages.length - 1; i >= 0; i -= 1) {
    35→    const msg = messages[i];
    36→    if (msg.role !== "user") continue;
    37→    const text = extractTextFromUiMessage(msg);
    38→    if (text) return text;
    39→  }
    40→  return;
    41→}
    42→
    43→/**
    44→ * Summarizes message parts for logging
    45→ */
    46→export function summarizeParts(parts: UIMessage["parts"]): string {
    47→  const counts = new Map<string, number>();
    48→  for (const part of parts) {
    49→    counts.set(part.type, (counts.get(part.type) ?? 0) + 1);
    50→  }
    51→  const summary = [...counts.entries()]
    52→    .map(([type, count]) => `${type}:${count}`)
    53→    .join(", ");
    54→
    55→  return summary.length ? `parts(${summary})` : "parts(empty)";
    56→}
